package com.ecommerce.search.config;

import co.elastic.clients.elasticsearch.ElasticsearchClient;
import co.elastic.clients.json.jackson.JacksonJsonpMapper;
import co.elastic.clients.transport.ElasticsearchTransport;
import co.elastic.clients.transport.rest_client.RestClientTransport;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.datatype.jsr310.JavaTimeModule;
import org.apache.http.Header;
import org.apache.http.HttpHost;
import org.apache.http.auth.AuthScope;
import org.apache.http.auth.UsernamePasswordCredentials;
import org.apache.http.impl.client.BasicCredentialsProvider;
import org.apache.http.message.BasicHeader;
import org.apache.http.ssl.SSLContextBuilder;
import org.apache.http.ssl.SSLContexts;
import org.elasticsearch.client.RestClient;
import org.elasticsearch.client.RestClientBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;

import javax.net.ssl.SSLContext;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.security.KeyStore;
import java.util.Base64;

@Configuration
public class ElasticsearchConfig {

    private static final Logger logger = LoggerFactory.getLogger(ElasticsearchConfig.class);

    private final ElasticsearchProperties properties;

    public ElasticsearchConfig(ElasticsearchProperties properties) {
        this.properties = properties;
        validateSecureConnection();
    }

    private void validateSecureConnection() {
        if (!"https".equalsIgnoreCase(properties.getScheme())) {
            throw new IllegalStateException(
                "Elasticsearch connection must use HTTPS. Unencrypted HTTP connections are not allowed. " +
                "Set elasticsearch.scheme=https in your configuration."
            );
        }
        logger.info("Elasticsearch configured with HTTPS encryption enabled.");
    }

    @Bean
    public RestClient restClient() {
        try {
            HttpHost httpHost = new HttpHost(
                properties.getHost(),
                properties.getPort(),
                properties.getScheme()
            );

            RestClientBuilder builder = RestClient.builder(httpHost);

            builder.setHttpClientConfigCallback(httpClientBuilder -> {
                // Configure SSL/TLS
                try {
                    SSLContext sslContext = buildSSLContext();
                    httpClientBuilder.setSSLContext(sslContext);
                } catch (Exception e) {
                    throw new RuntimeException("Failed to configure SSL context for Elasticsearch", e);
                }

                // Configure authentication
                String apiKey = properties.getApiKey();
                if (apiKey != null && !apiKey.isBlank()) {
                    // API key auth is handled via headers below
                    logger.info("Using API key authentication for Elasticsearch.");
                } else if (properties.getUsername() != null && properties.getPassword() != null) {
                    BasicCredentialsProvider credentialsProvider = new BasicCredentialsProvider();
                    credentialsProvider.setCredentials(
                        AuthScope.ANY,
                        new UsernamePasswordCredentials(
                            properties.getUsername(),
                            properties.getPassword()
                        )
                    );
                    httpClientBuilder.setDefaultCredentialsProvider(credentialsProvider);
                    logger.info("Using basic authentication for Elasticsearch.");
                } else {
                    throw new IllegalStateException(
                        "Elasticsearch authentication is required. Provide either API key or username/password."
                    );
                }

                return httpClientBuilder;
            });

            builder.setRequestConfigCallback(requestConfigBuilder ->
                requestConfigBuilder
                    .setConnectTimeout(properties.getConnectTimeout())
                    .setSocketTimeout(properties.getSocketTimeout())
            );

            // Add API key header if configured
            String apiKey = properties.getApiKey();
            if (apiKey != null && !apiKey.isBlank()) {
                Header[] defaultHeaders = new Header[]{
                    new BasicHeader("Authorization", "ApiKey " + apiKey)
                };
                builder.setDefaultHeaders(defaultHeaders);
            }

            return builder.build();

        } catch (Exception e) {
            throw new RuntimeException("Failed to create Elasticsearch REST client", e);
        }
    }

    private SSLContext buildSSLContext() throws Exception {
        String truststorePath = properties.getTruststorePath();
        String truststorePassword = properties.getTruststorePassword();

        if (truststorePath != null && !truststorePath.isBlank()) {
            Path path = Paths.get(truststorePath);
            if (!Files.exists(path)) {
                throw new IllegalStateException(
                    "Elasticsearch truststore file not found: " + truststorePath
                );
            }

            KeyStore trustStore = KeyStore.getInstance("PKCS12");
            try (InputStream is = Files.newInputStream(path)) {
                char[] password = truststorePassword != null ? truststorePassword.toCharArray() : null;
                trustStore.load(is, password);
            }

            return SSLContexts.custom()
                .loadTrustMaterial(trustStore, null)
                .build();
        }

        // Fallback to default SSL context (uses JVM's default truststore)
        logger.warn("No custom truststore configured. Using JVM default truststore for Elasticsearch TLS.");
        return SSLContextBuilder.create().build();
    }

    @Bean
    public ElasticsearchTransport elasticsearchTransport(RestClient restClient) {
        ObjectMapper objectMapper = new ObjectMapper();
        objectMapper.registerModule(new JavaTimeModule());
        return new RestClientTransport(restClient, new JacksonJsonpMapper(objectMapper));
    }

    @Bean
    public ElasticsearchClient elasticsearchClient(ElasticsearchTransport transport) {
        return new ElasticsearchClient(transport);
    }
}

