package com.ecommerce.search.service;

import co.elastic.clients.elasticsearch.ElasticsearchClient;
import co.elastic.clients.elasticsearch.indices.CreateIndexRequest;
import co.elastic.clients.elasticsearch.indices.ExistsRequest;
import com.ecommerce.search.config.ElasticsearchProperties;
import jakarta.annotation.PostConstruct;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.io.StringReader;

@Service
public class IndexManagementService {

    private static final Logger logger = LoggerFactory.getLogger(IndexManagementService.class);

    private final ElasticsearchClient client;
    private final ElasticsearchProperties properties;

    public IndexManagementService(ElasticsearchClient client, ElasticsearchProperties properties) {
        this.client = client;
        this.properties = properties;
    }

    @PostConstruct
    public void initializeIndices() {
        try {
            createProductIndex();
            createSearchQueryIndex();
            logger.info("Elasticsearch indices initialized successfully.");
        } catch (Exception e) {
            logger.error("Failed to initialize Elasticsearch indices", e);
            throw new RuntimeException("Failed to initialize Elasticsearch indices", e);
        }
    }

    private void createProductIndex() throws IOException {
        String indexName = properties.getIndices().getProducts();

        boolean exists = client.indices().exists(
            ExistsRequest.of(e -> e.index(indexName))
        ).value();

        if (!exists) {
            String mappings = """
            {
              "settings": {
                "number_of_shards": 2,
                "number_of_replicas": 1,
                "analysis": {
                  "analyzer": {
                    "product_analyzer": {
                      "type": "custom",
                      "tokenizer": "standard",
                      "filter": ["lowercase", "stop", "snowball", "edge_ngram_filter"]
                    },
                    "search_analyzer": {
                      "type": "custom",
                      "tokenizer": "standard",
                      "filter": ["lowercase", "stop", "snowball"]
                    }
                  },
                  "filter": {
                    "edge_ngram_filter": {
                      "type": "edge_ngram",
                      "min_gram": 2,
                      "max_gram": 20
                    }
                  }
                }
              },
              "mappings": {
                "properties": {
                  "name": {
                    "type": "text",
                    "analyzer": "product_analyzer",
                    "search_analyzer": "search_analyzer",
                    "fields": {
                      "keyword": { "type": "keyword" },
                      "suggest": {
                        "type": "completion"
                      }
                    }
                  },
                  "description": {
                    "type": "text",
                    "analyzer": "product_analyzer",
                    "search_analyzer": "search_analyzer"
                  },
                  "category": {
                    "type": "keyword",
                    "fields": {
                      "text": { "type": "text" }
                    }
                  },
                  "brand": {
                    "type": "keyword",
                    "fields": {
                      "text": { "type": "text" }
                    }
                  },
                  "price": { "type": "double" },
                  "originalPrice": { "type": "double" },
                  "currency": { "type": "keyword" },
                  "tags": { "type": "keyword" },
                  "attributes": {
                    "type": "object",
                    "enabled": true
                  },
                  "imageUrl": { "type": "keyword", "index": false },
                  "stockQuantity": { "type": "integer" },
                  "rating": { "type": "double" },
                  "reviewCount": { "type": "integer" },
                  "sku": { "type": "keyword" },
                  "active": { "type": "boolean" },
                  "created_at": { "type": "date" },
                  "updated_at": { "type": "date" }
                }
              }
            }
            """;

            client.indices().create(CreateIndexRequest.of(c ->
                c.index(indexName).withJson(new StringReader(mappings))
            ));

            logger.info("Created product index: {}", indexName);
        } else {
            logger.info("Product index already exists: {}", indexName);
        }
    }

    private void createSearchQueryIndex() throws IOException {
        String indexName = properties.getIndices().getSearchQueries();

        boolean exists = client.indices().exists(
            ExistsRequest.of(e -> e.index(indexName))
        ).value();

        if (!exists) {
            String mappings = """
            {
              "settings": {
                "number_of_shards": 1,
                "number_of_replicas": 1
              },
              "mappings": {
                "properties": {
                  "query_text": {
                    "type": "text",
                    "fields": {
                      "keyword": { "type": "keyword" }
                    }
                  },
                  "customer_id": { "type": "keyword" },
                  "session_id": { "type": "keyword" },
                  "filters": { "type": "object" },
                  "result_count": { "type": "long" },
                  "response_time_ms": { "type": "long" },
                  "timestamp": { "type": "date" },
                  "user_agent": { "type": "text", "index": false },
                  "ip_address": { "type": "ip" },
                  "sort_by": { "type": "keyword" },
                  "page": { "type": "integer" },
                  "page_size": { "type": "integer" }
                }
              }
            }
            """;

            client.indices().create(CreateIndexRequest.of(c ->
                c.index(indexName).withJson(new StringReader(mappings))
            ));

            logger.info("Created search query index: {}", indexName);
        } else {
            logger.info("Search query index already exists: {}", indexName);
        }
    }
}

