package com.ecommerce.search.service;

import co.elastic.clients.elasticsearch.ElasticsearchClient;
import co.elastic.clients.elasticsearch._types.Refresh;
import co.elastic.clients.elasticsearch.core.*;
import co.elastic.clients.elasticsearch.core.bulk.BulkOperation;
import co.elastic.clients.elasticsearch.core.bulk.BulkResponseItem;
import com.ecommerce.search.config.ElasticsearchProperties;
import com.ecommerce.search.exception.ProductNotFoundException;
import com.ecommerce.search.model.Product;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
public class ProductIndexingService {

    private static final Logger logger = LoggerFactory.getLogger(ProductIndexingService.class);

    private final ElasticsearchClient client;
    private final String productIndex;

    public ProductIndexingService(ElasticsearchClient client, ElasticsearchProperties properties) {
        this.client = client;
        this.productIndex = properties.getIndices().getProducts();
    }

    public Product indexProduct(Product product) throws IOException {
        if (product.getId() == null || product.getId().isBlank()) {
            product.setId(UUID.randomUUID().toString());
        }
        product.setUpdatedAt(Instant.now());
        if (product.getCreatedAt() == null) {
            product.setCreatedAt(Instant.now());
        }

        IndexResponse response = client.index(i -> i
            .index(productIndex)
            .id(product.getId())
            .document(product)
            .refresh(Refresh.WaitFor)
        );

        logger.info("Indexed product {} with result: {}", product.getId(), response.result().jsonValue());
        return product;
    }

    public List<Product> bulkIndexProducts(List<Product> products) throws IOException {
        List<BulkOperation> operations = new ArrayList<>();

        for (Product product : products) {
            if (product.getId() == null || product.getId().isBlank()) {
                product.setId(UUID.randomUUID().toString());
            }
            product.setUpdatedAt(Instant.now());
            if (product.getCreatedAt() == null) {
                product.setCreatedAt(Instant.now());
            }

            final Product p = product;
            operations.add(BulkOperation.of(op -> op
                .index(idx -> idx
                    .index(productIndex)
                    .id(p.getId())
                    .document(p)
                )
            ));
        }

        BulkResponse bulkResponse = client.bulk(b -> b
            .operations(operations)
            .refresh(Refresh.WaitFor)
        );

        if (bulkResponse.errors()) {
            for (BulkResponseItem item : bulkResponse.items()) {
                if (item.error() != null) {
                    logger.error("Bulk index error for product {}: {}",
                        item.id(), item.error().reason());
                }
            }
        }

        logger.info("Bulk indexed {} products, took {}ms", products.size(), bulkResponse.took());
        return products;
    }

    public Product getProduct(String id) throws IOException {
        GetResponse<Product> response = client.get(g -> g
            .index(productIndex)
            .id(id),
            Product.class
        );

        if (!response.found()) {
            throw new ProductNotFoundException("Product not found with id: " + id);
        }

        Product product = response.source();
        if (product != null) {
            product.setId(response.id());
        }
        return product;
    }

    public Product updateProduct(String id, Product product) throws IOException {
        // Verify product exists
        getProduct(id);

        product.setId(id);
        product.setUpdatedAt(Instant.now());

        UpdateResponse<Product> response = client.update(u -> u
            .index(productIndex)
            .id(id)
            .doc(product)
            .docAsUpsert(true)
            .refresh(Refresh.WaitFor),
            Product.class
        );

        logger.info("Updated product {} with result: {}", id, response.result().jsonValue());
        return product;
    }

    public void deleteProduct(String id) throws IOException {
        DeleteResponse response = client.delete(d -> d
            .index(productIndex)
            .id(id)
            .refresh(Refresh.WaitFor)
        );

        if ("not_found".equals(response.result().jsonValue())) {
            throw new ProductNotFoundException("Product not found with id: " + id);
        }

        logger.info("Deleted product {} with result: {}", id, response.result().jsonValue());
    }
}

