package com.ecommerce.search.service;

import co.elastic.clients.elasticsearch.ElasticsearchClient;
import co.elastic.clients.elasticsearch._types.FieldValue;
import co.elastic.clients.elasticsearch._types.SortOrder;
import co.elastic.clients.elasticsearch._types.aggregations.*;
import co.elastic.clients.elasticsearch._types.query_dsl.*;
import co.elastic.clients.elasticsearch.core.SearchResponse;
import co.elastic.clients.elasticsearch.core.search.Hit;
import co.elastic.clients.elasticsearch.core.search.CompletionSuggestOption;
import com.ecommerce.search.config.ElasticsearchProperties;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.model.SearchRequest;
import com.ecommerce.search.model.SearchQuery;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class ProductSearchService {

    private static final Logger logger = LoggerFactory.getLogger(ProductSearchService.class);

    private final ElasticsearchClient client;
    private final String productIndex;
    private final SearchQueryService searchQueryService;

    public ProductSearchService(ElasticsearchClient client,
                                ElasticsearchProperties properties,
                                SearchQueryService searchQueryService) {
        this.client = client;
        this.productIndex = properties.getIndices().getProducts();
        this.searchQueryService = searchQueryService;
    }

    public com.ecommerce.search.model.SearchResponse search(SearchRequest request) throws IOException {
        long startTime = System.currentTimeMillis();

        // Build the query
        BoolQuery.Builder boolQueryBuilder = new BoolQuery.Builder();

        // Only show active products
        boolQueryBuilder.filter(f -> f.term(t -> t.field("active").value(true)));

        // Full-text search
        if (request.getQuery() != null && !request.getQuery().isBlank()) {
            String sanitizedQuery = sanitizeSearchQuery(request.getQuery());

            boolQueryBuilder.must(m -> m
                .multiMatch(mm -> mm
                    .query(sanitizedQuery)
                    .fields("name^3", "description^1", "brand^2", "category^2", "tags^1.5")
                    .type(TextQueryType.BestFields)
                    .fuzziness("AUTO")
                    .prefixLength(2)
                    .minimumShouldMatch("75%")
                )
            );

            // Boost exact matches
            boolQueryBuilder.should(s -> s
                .matchPhrase(mp -> mp
                    .field("name")
                    .query(sanitizedQuery)
                    .boost(5.0f)
                )
            );
        }

        // Category filter
        if (request.getCategory() != null && !request.getCategory().isBlank()) {
            boolQueryBuilder.filter(f -> f
                .term(t -> t.field("category").value(request.getCategory()))
            );
        }

        // Brand filter
        if (request.getBrand() != null && !request.getBrand().isBlank()) {
            boolQueryBuilder.filter(f -> f
                .term(t -> t.field("brand").value(request.getBrand()))
            );
        }

        // Price range filter
        if (request.getMinPrice() != null || request.getMaxPrice() != null) {
            boolQueryBuilder.filter(f -> f
                .range(r -> {
                    r.field("price");
                    if (request.getMinPrice() != null) {
                        r.gte(co.elastic.clients.json.JsonData.of(request.getMinPrice()));
                    }
                    if (request.getMaxPrice() != null) {
                        r.lte(co.elastic.clients.json.JsonData.of(request.getMaxPrice()));
                    }
                    return r;
                })
            );
        }

        // Rating filter
        if (request.getMinRating() != null) {
            boolQueryBuilder.filter(f -> f
                .range(r -> r
                    .field("rating")
                    .gte(co.elastic.clients.json.JsonData.of(request.getMinRating()))
                )
            );
        }

        // Tags filter
        if (request.getTags() != null && !request.getTags().isEmpty()) {
            List<FieldValue> tagValues = request.getTags().stream()
                .map(FieldValue::of)
                .collect(Collectors.toList());
            boolQueryBuilder.filter(f -> f
                .terms(t -> t
                    .field("tags")
                    .terms(tv -> tv.value(tagValues))
                )
            );
        }

        // Custom attribute filters
        if (request.getFilters() != null) {
            for (Map.Entry<String, String> entry : request.getFilters().entrySet()) {
                String field = "attributes." + sanitizeFieldName(entry.getKey());
                String value = entry.getValue();
                boolQueryBuilder.filter(f -> f
                    .term(t -> t.field(field).value(value))
                );
            }
        }

        // In-stock boost
        boolQueryBuilder.should(s -> s
            .range(r -> r
                .field("stockQuantity")
                .gt(co.elastic.clients.json.JsonData.of(0))
                .boost(2.0f)
            )
        );

        Query finalQuery = Query.of(q -> q.bool(boolQueryBuilder.build()));

        // Execute search with aggregations
        SearchResponse<Product> searchResponse = client.search(s -> {
            s.index(productIndex)
                .query(finalQuery)
                .from(request.getPage() * request.getPageSize())
                .size(request.getPageSize())
                // Aggregations for faceted navigation
                .aggregations("categories", a -> a
                    .terms(t -> t.field("category").size(50))
                )
                .aggregations("brands", a -> a
                    .terms(t -> t.field("brand").size(50))
                )
                .aggregations("tags", a -> a
                    .terms(t -> t.field("tags").size(100))
                )
                .aggregations("price_ranges", a -> a
                    .range(r -> r
                        .field("price")
                        .ranges(
                            rng -> rng.key("Under $25").to("25"),
                            rng -> rng.key("$25 - $50").from("25").to("50"),
                            rng -> rng.key("$50 - $100").from("50").to("100"),
                            rng -> rng.key("$100 - $200").from("100").to("200"),
                            rng -> rng.key("$200 - $500").from("200").to("500"),
                            rng -> rng.key("Over $500").from("500")
                        )
                    )
                )
                .aggregations("avg_price", a -> a
                    .avg(avg -> avg.field("price"))
                )
                .aggregations("rating_ranges", a -> a
                    .range(r -> r
                        .field("rating")
                        .ranges(
                            rng -> rng.key("4+ Stars").from("4"),
                            rng -> rng.key("3+ Stars").from("3"),
                            rng -> rng.key("2+ Stars").from("2"),
                            rng -> rng.key("1+ Stars").from("1")
                        )
                    )
                )
                .highlight(h -> h
                    .fields("name", hf -> hf.preTags("<em>").postTags("</em>"))
                    .fields("description", hf -> hf
                        .preTags("<em>").postTags("</em>")
                        .fragmentSize(150)
                        .numberOfFragments(3)
                    )
                );

            // Sorting
            applySorting(s, request);

            return s;
        }, Product.class);

        // Build response
        com.ecommerce.search.model.SearchResponse response = buildSearchResponse(
            searchResponse, request, startTime
        );

        // Log search query asynchronously
        logSearchQuery(request, response, startTime);

        return response;
    }

    public List<String> suggest(String prefix, int size) throws IOException {
        if (prefix == null || prefix.isBlank()) {
            return Collections.emptyList();
        }

        String sanitizedPrefix = sanitizeSearchQuery(prefix);

        SearchResponse<Product> response = client.search(s -> s
            .index(productIndex)
            .suggest(sg -> sg
                .suggesters("product-suggest", fs -> fs
                    .prefix(sanitizedPrefix)
                    .completion(cs -> cs
                        .field("name.suggest")
                        .size(size)
                        .skipDuplicates(true)
                        .fuzzy(f -> f
                            .fuzziness("AUTO")
                            .prefixLength(2)
                        )
                    )
                )
            ),
            Product.class
        );

        List<String> suggestions = new ArrayList<>();
        if (response.suggest() != null && response.suggest().containsKey("product-suggest")) {
            response.suggest().get("product-suggest").forEach(suggestion -> {
                suggestion.completion().options().forEach(option -> {
                    suggestions.add(option.text());
                });
            });
        }

        return suggestions;
    }

    private void applySorting(co.elastic.clients.elasticsearch.core.SearchRequest.Builder builder,
                              SearchRequest request) {
        String sortBy = request.getSortBy();
        SortOrder sortOrder = "asc".equalsIgnoreCase(request.getSortOrder())
            ? SortOrder.Asc : SortOrder.Desc;

        switch (sortBy != null ? sortBy.toLowerCase() : "relevance") {
            case "price":
                builder.sort(s -> s.field(f -> f.field("price").order(sortOrder)));
                break;
            case "rating":
                builder.sort(s -> s.field(f -> f.field("rating").order(SortOrder.Desc)));
                break;
            case "newest":
                builder.sort(s -> s.field(f -> f.field("created_at").order(SortOrder.Desc)));
                break;
            case "name":
                builder.sort(s -> s.field(f -> f.field("name.keyword").order(sortOrder)));
                break;
            case "popularity":
                builder.sort(s -> s.field(f -> f.field("reviewCount").order(SortOrder.Desc)));
                break;
            case "relevance":
            default:
                builder.sort(s -> s.score(sc -> sc.order(SortOrder.Desc)));
                break;
        }
    }

    private com.ecommerce.search.model.SearchResponse buildSearchResponse(
            SearchResponse<Product> searchResponse,
            SearchRequest request,
            long startTime) {

        com.ecommerce.search.model.SearchResponse response = new com.ecommerce.search.model.SearchResponse();

        // Extract products
        List<Product> products = new ArrayList<>();
        for (Hit<Product> hit : searchResponse.hits().hits()) {
            Product product = hit.source();
            if (product != null) {
                product.setId(hit.id());
                products.add(product);
            }
        }
        response.setProducts(products);

        // Total hits
        long totalHits = searchResponse.hits().total() != null
            ? searchResponse.hits().total().value() : 0;
        response.setTotalHits(totalHits);

        // Pagination
        response.setPage(request.getPage());
        response.setPageSize(request.getPageSize());
        response.setTotalPages((int) Math.ceil((double) totalHits / request.getPageSize()));

        // Response time
        response.setResponseTimeMs(System.currentTimeMillis() - startTime);

        // Extract facets
        Map<String, List<com.ecommerce.search.model.SearchResponse.FacetBucket>> facets = new LinkedHashMap<>();

        // Category facets
        if (searchResponse.aggregations().containsKey("categories")) {
            facets.put("categories", extractStringTermBuckets(
                searchResponse.aggregations().get("categories")
            ));
        }

        // Brand facets
        if (searchResponse.aggregations().containsKey("brands")) {
            facets.put("brands", extractStringTermBuckets(
                searchResponse.aggregations().get("brands")
            ));
        }

        // Tags facets
        if (searchResponse.aggregations().containsKey("tags")) {
            facets.put("tags", extractStringTermBuckets(
                searchResponse.aggregations().get("tags")
            ));
        }

        // Price range facets
        if (searchResponse.aggregations().containsKey("price_ranges")) {
            facets.put("price_ranges", extractRangeBuckets(
                searchResponse.aggregations().get("price_ranges")
            ));
        }

        // Rating range facets
        if (searchResponse.aggregations().containsKey("rating_ranges")) {
            facets.put("rating_ranges", extractRangeBuckets(
                searchResponse.aggregations().get("rating_ranges")
            ));
        }

        response.setFacets(facets);

        return response;
    }

    private List<com.ecommerce.search.model.SearchResponse.FacetBucket> extractStringTermBuckets(
            Aggregate aggregate) {
        List<com.ecommerce.search.model.SearchResponse.FacetBucket> buckets = new ArrayList<>();
        if (aggregate.isSterms()) {
            for (StringTermsBucket bucket : aggregate.sterms().buckets().array()) {
                buckets.add(new com.ecommerce.search.model.SearchResponse.FacetBucket(
                    bucket.key().stringValue(), bucket.docCount()
                ));
            }
        }
        return buckets;
    }

    private List<com.ecommerce.search.model.SearchResponse.FacetBucket> extractRangeBuckets(
            Aggregate aggregate) {
        List<com.ecommerce.search.model.SearchResponse.FacetBucket> buckets = new ArrayList<>();
        if (aggregate.isRange()) {
            for (RangeBucket bucket : aggregate.range().buckets().array()) {
                if (bucket.docCount() > 0) {
                    buckets.add(new com.ecommerce.search.model.SearchResponse.FacetBucket(
                        bucket.key(), bucket.docCount()
                    ));
                }
            }
        }
        return buckets;
    }

    private void logSearchQuery(SearchRequest request,
                                com.ecommerce.search.model.SearchResponse response,
                                long startTime) {
        try {
            SearchQuery searchQuery = new SearchQuery();
            searchQuery.setQueryText(request.getQuery());
            searchQuery.setCustomerId(request.getCustomerId());
            searchQuery.setSessionId(request.getSessionId());
            searchQuery.setFilters(request.getFilters());
            searchQuery.setResultCount(response.getTotalHits());
            searchQuery.setResponseTimeMs(System.currentTimeMillis() - startTime);
            searchQuery.setSortBy(request.getSortBy());
            searchQuery.setPage(request.getPage());
            searchQuery.setPageSize(request.getPageSize());

            searchQueryService.logSearchQuery(searchQuery);
        } catch (Exception e) {
            logger.warn("Failed to log search query", e);
        }
    }

    private String sanitizeSearchQuery(String query) {
        if (query == null) return "";
        // Remove Elasticsearch special characters to prevent injection
        return query.replaceAll("[+\\-=&|><!(){}\\[\\]^\"~*?:\\\\/]", " ")
                    .replaceAll("\\s+", " ")
                    .trim();
    }

    private String sanitizeFieldName(String fieldName) {
        if (fieldName == null) return "";
        return fieldName.replaceAll("[^a-zA-Z0-9_.]", "");
    }
}

