package com.ecommerce.search.service;

import co.elastic.clients.elasticsearch.ElasticsearchClient;
import co.elastic.clients.elasticsearch._types.SortOrder;
import co.elastic.clients.elasticsearch.core.IndexResponse;
import co.elastic.clients.elasticsearch.core.SearchResponse;
import co.elastic.clients.elasticsearch.core.search.Hit;
import com.ecommerce.search.config.ElasticsearchProperties;
import com.ecommerce.search.model.SearchQuery;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.util.*;
import java.util.stream.Collectors;

@Service
public class SearchQueryService {

    private static final Logger logger = LoggerFactory.getLogger(SearchQueryService.class);

    private final ElasticsearchClient client;
    private final String searchQueryIndex;

    public SearchQueryService(ElasticsearchClient client, ElasticsearchProperties properties) {
        this.client = client;
        this.searchQueryIndex = properties.getIndices().getSearchQueries();
    }

    public void logSearchQuery(SearchQuery searchQuery) throws IOException {
        if (searchQuery.getId() == null) {
            searchQuery.setId(UUID.randomUUID().toString());
        }

        IndexResponse response = client.index(i -> i
            .index(searchQueryIndex)
            .id(searchQuery.getId())
            .document(searchQuery)
        );

        logger.debug("Logged search query: {} with result: {}",
            searchQuery.getQueryText(), response.result().jsonValue());
    }

    public List<String> getPopularSearches(int size) throws IOException {
        SearchResponse<SearchQuery> response = client.search(s -> s
            .index(searchQueryIndex)
            .size(0)
            .aggregations("popular_queries", a -> a
                .terms(t -> t
                    .field("query_text.keyword")
                    .size(size)
                    .minDocCount(2)
                )
            ),
            SearchQuery.class
        );

        List<String> popularSearches = new ArrayList<>();
        if (response.aggregations().containsKey("popular_queries")) {
            response.aggregations().get("popular_queries").sterms().buckets().array()
                .forEach(bucket -> popularSearches.add(bucket.key().stringValue()));
        }

        return popularSearches;
    }

    public List<SearchQuery> getRecentSearches(String customerId, int size) throws IOException {
        SearchResponse<SearchQuery> response = client.search(s -> s
            .index(searchQueryIndex)
            .query(q -> q
                .term(t -> t
                    .field("customer_id")
                    .value(customerId)
                )
            )
            .sort(so -> so.field(f -> f.field("timestamp").order(SortOrder.Desc)))
            .size(size),
            SearchQuery.class
        );

        return response.hits().hits().stream()
            .map(Hit::source)
            .filter(Objects::nonNull)
            .collect(Collectors.toList());
    }

    public Map<String, Object> getSearchAnalytics() throws IOException {
        SearchResponse<SearchQuery> response = client.search(s -> s
            .index(searchQueryIndex)
            .size(0)
            .aggregations("total_searches", a -> a
                .valueCount(vc -> vc.field("query_text.keyword"))
            )
            .aggregations("unique_queries", a -> a
                .cardinality(c -> c.field("query_text.keyword"))
            )
            .aggregations("avg_response_time", a -> a
                .avg(avg -> avg.field("response_time_ms"))
            )
            .aggregations("avg_results", a -> a
                .avg(avg -> avg.field("result_count"))
            )
            .aggregations("zero_result_queries", a -> a
                .filter(f -> f
                    .term(t -> t.field("result_count").value(0))
                )
            )
            .aggregations("searches_over_time", a -> a
                .dateHistogram(dh -> dh
                    .field("timestamp")
                    .calendarInterval(co.elastic.clients.elasticsearch._types.aggregations.CalendarInterval.Hour)
                )
            ),
            SearchQuery.class
        );

        Map<String, Object> analytics = new LinkedHashMap<>();

        if (response.aggregations().containsKey("total_searches")) {
            analytics.put("totalSearches",
                (long) response.aggregations().get("total_searches").valueCount().value());
        }
        if (response.aggregations().containsKey("unique_queries")) {
            analytics.put("uniqueQueries",
                response.aggregations().get("unique_queries").cardinality().value());
        }
        if (response.aggregations().containsKey("avg_response_time")) {
            analytics.put("avgResponseTimeMs",
                response.aggregations().get("avg_response_time").avg().value());
        }
        if (response.aggregations().containsKey("avg_results")) {
            analytics.put("avgResultCount",
                response.aggregations().get("avg_results").avg().value());
        }
        if (response.aggregations().containsKey("zero_result_queries")) {
            analytics.put("zeroResultQueries",
                response.aggregations().get("zero_result_queries").filter().docCount());
        }

        return analytics;
    }
}

