package com.ecommerce.search.controller;

import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;

@RestController
@RequestMapping("/api/products")
public class ProductController {

    private final ProductIndexingService indexingService;

    public ProductController(ProductIndexingService indexingService) {
        this.indexingService = indexingService;
    }

    @PostMapping
    public ResponseEntity<Product> createProduct(@Valid @RequestBody Product product) throws IOException {
        Product indexed = indexingService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED).body(indexed);
    }

    @PostMapping("/bulk")
    public ResponseEntity<List<Product>> bulkCreateProducts(@Valid @RequestBody List<Product> products)
            throws IOException {
        if (products.size() > 1000) {
            throw new IllegalArgumentException("Bulk indexing is limited to 1000 products per request");
        }
        List<Product> indexed = indexingService.bulkIndexProducts(products);
        return ResponseEntity.status(HttpStatus.CREATED).body(indexed);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = indexingService.getProduct(id);
        return ResponseEntity.ok(product);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Product> updateProduct(@PathVariable String id,
                                                  @Valid @RequestBody Product product) throws IOException {
        Product updated = indexingService.updateProduct(id, product);
        return ResponseEntity.ok(updated);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable String id) throws IOException {
        indexingService.deleteProduct(id);
        return ResponseEntity.noContent().build();
    }
}

